SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";

-- Desativa o autocommit para iniciar transações manualmente
SET AUTOCOMMIT = 0;

-- Inicia uma transação
START TRANSACTION;

-- Define o fuso horário para -03:00
SET time_zone = "-03:00";

-- Criação do banco de dados, se não existir
CREATE DATABASE IF NOT EXISTS {{ $json.NOME_cliente }}
  DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci;

-- Finaliza a transação
COMMIT;

CREATE TABLE IF NOT EXISTS {{ $json.NOME_cliente }}.`email_abriu` (
  `cod_lancamento` VARCHAR(10) NOT NULL,
  `email` VARCHAR(255) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS {{ $json.NOME_cliente }}.`email_devolvidos` (
  `cod_lancamento` VARCHAR(10) NOT NULL,
  `email` VARCHAR(255) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS {{ $json.NOME_cliente }}.`googleads` (
  `ad_id` int NOT NULL,
  `ad_name` varchar(100) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

COMMIT;

-- Seleciona o banco de dados para uso
USE {{ $json.NOME_cliente }};

-- DROP VIEW IF EXISTS leads_e_vendasFIRST;

CREATE VIEW `leads_e_vendasFIRST` AS
SELECT L.cod_lancamento,L.date,L.email,L.`utm_source`,L.`utm_campaign`,L.`utm_medium`,L.`utm_content`,L.`utm_publico`,L.`utm_term` , V.`email_do_comprador`, V.`valor_de_compra_sem_impostos`, V.`comissao_bruta_sem_impostos`
FROM `first_leads` AS L LEFT JOIN `hotmart20` AS V ON L.email = V.`email_do_comprador`;


COMMIT;

-- Seleciona o banco de dados para uso
USE {{ $json.NOME_cliente }};

-- DROP VIEW IF EXISTS leads_e_vendasLAST;

CREATE VIEW `leads_e_vendasLAST` AS
