FROM `last_leads` AS L LEFT JOIN `hotmart20` AS V ON L.email = V.`email_do_comprador`;


COMMIT;

-- Seleciona o banco de dados para uso
USE {{ $json.NOME_cliente }};
-- DROP VIEW IF EXISTS `first_leads`;
CREATE VIEW first_leads AS
WITH RankedLeads AS (
    SELECT 
        L1.*,
        ROW_NUMBER() OVER (PARTITION BY L1.email_cod_lancamento ORDER BY L1.datetime DESC, L1.lead_counter ASC) AS rn
    FROM `lista_leads` AS L1
    INNER JOIN (
        SELECT email_cod_lancamento, MAX(`datetime`) AS max_datetime
        FROM `lista_leads`
        GROUP BY email_cod_lancamento
    ) AS L2 ON L1.email_cod_lancamento = L2.email_cod_lancamento
        AND L1.datetime = L2.max_datetime
)
SELECT *
FROM RankedLeads
WHERE rn = 1;

COMMIT;

-- Seleciona o banco de dados para uso
